using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _sut;

    public OrderServiceTests()
    {
        _sut = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    #region CreateOrder — happy path

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectCustomerId()
    {
        // Arrange
        var items = CreateItems(("Widget", 9.99m, 2));

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual("cust-1", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithNonEmptyId()
    {
        var items = CreateItems(("Widget", 9.99m, 1));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCreatedAtToRecentUtcTime()
    {
        var before = DateTime.UtcNow;
        var items = CreateItems(("Widget", 5.00m, 1));

        var order = _sut.CreateOrder("cust-1", items);

        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            $"CreatedAt {order.CreatedAt} should be between {before} and {after}.");
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_CalculatesTotalCorrectly()
    {
        // price * quantity = 10.00 * 3 = 30.00
        var items = CreateItems(("Gadget", 10.00m, 3));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(30.00m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithMultipleItems_SumsTotalCorrectly()
    {
        // (5 * 2) + (3 * 4) = 10 + 12 = 22
        var items = CreateItems(("A", 5.00m, 2), ("B", 3.00m, 4));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(22.00m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_StoresAllItemsOnOrder()
    {
        var items = CreateItems(("X", 1m, 1), ("Y", 2m, 1), ("Z", 3m, 1));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(3, order.Items.Count);
    }

    #endregion

    #region CreateOrder — validation

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 1m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder(null!, items));

        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder("cust-1", null!));

        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsExactly<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", []));
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_AfterCreating_ReturnsSameOrder()
    {
        var items = CreateItems(("Widget", 5m, 1));
        var created = _sut.CreateOrder("cust-1", items);

        var retrieved = _sut.GetOrder(created.Id);

        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
    }

    [TestMethod]
    public void GetOrder_WithNonexistentId_ReturnsNull()
    {
        var result = _sut.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_WithNoOrders_ReturnsEmptyList()
    {
        var result = _sut.GetOrdersByCustomer("cust-unknown");

        Assert.AreEqual(0, result.Count);
    }

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyMatchingOrders()
    {
        var items = CreateItems(("W", 1m, 1));
        _sut.CreateOrder("cust-A", items);
        _sut.CreateOrder("cust-A", items);
        _sut.CreateOrder("cust-B", items);

        var result = _sut.GetOrdersByCustomer("cust-A");

        Assert.AreEqual(2, result.Count);
        Assert.IsTrue(result.All(o => o.CustomerId == "cust-A"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_DoesNotReturnOtherCustomerOrders()
    {
        var items = CreateItems(("W", 1m, 1));
        _sut.CreateOrder("cust-A", items);

        var result = _sut.GetOrdersByCustomer("cust-B");

        Assert.AreEqual(0, result.Count);
    }

    #endregion

    #region Multiple orders / isolation

    [TestMethod]
    public void CreateOrder_CalledMultipleTimes_AssignsUniqueIds()
    {
        var items = CreateItems(("W", 1m, 1));

        var order1 = _sut.CreateOrder("cust-1", items);
        var order2 = _sut.CreateOrder("cust-1", items);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    #endregion
}

